import SettingsPage from "./pages/SettingsPage";
import LeaderboardPage from "./pages/LeaderboardPage";
import LocalPlaylistPage from "./pages/LocalPlaylistPage";
import NowPlayingPage from "./pages/NowPlayingPage";
import QueuePage from "./pages/QueuePage";
import PodcastsPage from "./pages/PodcastsPage";
import PublicProfilePage from "./pages/PublicProfilePage";
import NotFound from "./pages/NotFound";

const queryClient = new QueryClient();

function ProtectedRoute({ children }: { children: React.ReactNode }) {
  const { isAuthenticated, loading } = useAuth();
  if (loading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-primary animate-pulse text-lg">Loading...</div>
      </div>
    );
  }
  if (!isAuthenticated) return <Navigate to="/login" replace />;
  return <>{children}</>;
}

function PublicRoute({ children }: { children: React.ReactNode }) {
  const { isAuthenticated, loading } = useAuth();
  if (loading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-primary animate-pulse text-lg">Loading...</div>
      </div>
    );
  }
  if (isAuthenticated) return <Navigate to="/" replace />;
  return <>{children}</>;
}

const AppRoutes = () => {
  return (
    <Routes>
      <Route path="/login" element={<PublicRoute><LoginPage /></PublicRoute>} />
      <Route path="/callback" element={<CallbackPage />} />
      <Route path="/" element={<ProtectedRoute><MainLayout><Index /></MainLayout></ProtectedRoute>} />
      <Route path="/search" element={<ProtectedRoute><MainLayout><Search /></MainLayout></ProtectedRoute>} />
      <Route path="/library" element={<ProtectedRoute><MainLayout><LibraryPage /></MainLayout></ProtectedRoute>} />
      <Route path="/playlist/:id" element={<ProtectedRoute><MainLayout><PlaylistPage /></MainLayout></ProtectedRoute>} />
      <Route path="/local-playlist/:id" element={<ProtectedRoute><MainLayout><LocalPlaylistPage /></MainLayout></ProtectedRoute>} />
      <Route path="/liked" element={<ProtectedRoute><MainLayout><LikedSongs /></MainLayout></ProtectedRoute>} />
      <Route path="/profile" element={<ProtectedRoute><MainLayout><ProfilePage /></MainLayout></ProtectedRoute>} />
      <Route path="/settings" element={<ProtectedRoute><MainLayout><SettingsPage /></MainLayout></ProtectedRoute>} />
      <Route path="/leaderboard" element={<ProtectedRoute><MainLayout><LeaderboardPage /></MainLayout></ProtectedRoute>} />
      <Route path="/now-playing" element={<ProtectedRoute><MainLayout><NowPlayingPage /></MainLayout></ProtectedRoute>} />
      <Route path="/queue" element={<ProtectedRoute><MainLayout><QueuePage /></MainLayout></ProtectedRoute>} />
      <Route path="/podcasts" element={<ProtectedRoute><MainLayout><PodcastsPage /></MainLayout></ProtectedRoute>} />
      <Route path="/user/:id" element={<ProtectedRoute><MainLayout><PublicProfilePage /></MainLayout></ProtectedRoute>} />
      <Route path="*" element={<NotFound />} />
    </Routes>
  );
};

const App = () => (
  <QueryClientProvider client={queryClient}>
    <TooltipProvider>
      <Toaster />
      <Sonner />
      <ThemeProvider>
        <SettingsProvider>
          <AuthProvider>
            <LocalLibraryProvider>
              <PlayerProvider>
                <BrowserRouter>
                  <AppRoutes />
                </BrowserRouter>
              </PlayerProvider>
            </LocalLibraryProvider>
          </AuthProvider>
        </SettingsProvider>
      </ThemeProvider>
    </TooltipProvider>
  </QueryClientProvider>
);

export default App;
